stringc_labeled.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	if DB.getChild(window.getDatabaseNode(), "realm") then
		local realmFound = false;
		local charRealm = DB.getValue(window.getDatabaseNode(), "realm", "");
		local realmList = Rules_Spells.RealmList();
		for i, r in pairs(realmList) do
			if string.lower(string.sub(r,1,4)) == string.lower(string.sub(charRealm,1,4)) then
				realmFound = true;
				charRealm = r;
			end								
		end
		if realmFound == true then
			setValue(charRealm);
		else
			setValue(realmList[1]);
		end
	end
end

button_text_sm.script:
function onButtonPress()
	local spellListNodeNames = Rules_Spells.SpellListNodesListByClass(window.spellclass.getValue());
	if spellListNodeNames then
		for i, nodeName in pairs(spellListNodeNames) do
			window.spells.addSpell(nodeName);
		end
	end
end

function onButtonPress()
	local spellListNodeNames = Rules_Spells.SpellListNodesListByListName(window.spelllist.getValue());
	if spellListNodeNames then
		for i, nodeName in pairs(spellListNodeNames) do
			window.spells.addSpell(nodeName);
		end
	end
end

windowlist.script:
					function addSpell(source)
						local newentry;
						local newnode;
						local prof;
						local cls;

						--[[ Prevent duplicate named lists ]]
						local newname = DB.getValue(source, "name", "");
						if newname ~= "" then
							for i,win in ipairs(getWindows()) do
								if win.name.getValue()==newname then
									--[[ duplicate, warn the user and fail ]]
									Comm.deliverChatMessage({font="systemfont",text="Spell list '" .. newname .. "' is already known"});
									return nil;
								end
							end
						end

						newentry = createWindow();
						newnode = newentry.getDatabaseNode();
						prof = string.lower(DB.getValue(window.getDatabaseNode(), "profession", ""));
						cls = string.lower(DB.getValue(source, "class", ""));

						--[[ Descriptive fields ]]
						local sSpellListName = DB.getValue(source, "name", "");
						local sSpellListClass = DB.getValue(source, "class", "");
						local sSpellListRealm = DB.getValue(source, "realm", "");
						local sSpellListType = DB.getValue(source, "type", "");

						if sSpellListClass == "" and sSpellListRealm == "" and sSpellListType ~= "" then
							sSpellListClass, sSpellListRealm = Rules_Spells.GetClassAndRealm(sSpellListType);
						end

						newentry.name.setValue(sSpellListName);
						newentry.class.setValue(sSpellListClass);
						newentry.realm.setValue(sSpellListRealm);

						--[[ Shortcut ]]
						newentry.open.setTarget(DB.getPath(source));

						--[[ Base list? ]]
						newentry.base.setValue(0);
						if string.find(cls,prof,1,true) then
							newentry.base.setValue(1);
							--[[ prevent a false positive if a Healer chooses a Lay Healer list ]]
							if prof=="healer" and string.find(cls,"lay healer",1,true) then
								newentry.base.setValue(0);
							end
						end

						--[[ re-initialise 
						newentry.onInit(); ]]

						return newentry;
					end

					function onDrop(x, y, draginfo)
						if draginfo.isType("spelllist") then
							local win = draginfo.getCustomData();
							local source = win.getDatabaseNode();
							addSpell(source);
							return true;
						elseif draginfo.isType("shortcut") then
							local class = draginfo.getShortcutData();
							local source = draginfo.getDatabaseNode();
							if source and class == "spelllist" then
								addSpell(source);
								return true;
							end
						end
						return false;
					end

					function onInit()
						resetMenuItems();
						registerMenuItem("Create List","insert",5);
					end

					function onMenuSelection(item)
						if item and item==5 then
							local win = createWindow();
							local node = win.getDatabaseNode();
							win.open.setValue("spelllist", DB.getPath(node));
						end
					end

windowclass.script:
			function onInit()
				if super and super.onInit then
					super.onInit();
				end
				local node = getDatabaseNode();
				DB.addHandler(DB.getPath(node, "class"), "onUpdate", self.updateType);
				DB.addHandler(DB.getPath(node, "realm"), "onUpdate", self.updateType);
				self.updateType();
				DB.addHandler(DB.getPath(node, "open"), "onUpdate", self.updateCustom);
				self.updateCustom();
			end

			function isCustom()
				local class,path = open.getValue();
				if path == "" or path == getDatabasePath() then
					return true;
				else
					return false;
				end
			end

			function updateCustom()
				if isCustom() then
					custom.setValue(1);
				else
					custom.setValue(0);
				end
			end

			function updateType()
				local cls = class.getValue();
				if cls=="Open" or cls=="Closed" then
					type.setValue(cls .. " " .. realm.getValue());
				else
					type.setValue(cls);
				end
			end

stringfield.script:
					local nESFTotal = 0;
					
					function action(draginfo)
						local charNode = DB.getChild(window.getDatabaseNode(), "...");
						local rActor = ActorManager.resolveActor(charNode);
						local sClass, sRecordName = window.open.getValue();
						local sRealm = window.realm.getValue();
						local nESFTotal = window.esf.getValue();
						if nESFTotal < 0 then
							nESFTotal = 0;
						end

						ActionBaseCasting.performRoll(draginfo, rActor, getValue(), sRecordName, sRealm, Rules_Spells.GetSpellFailure(nESFTotal));

						return true;
					end

					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end

					function onDoubleClick(x,y)
						return action();
					end

stringfieldX.script:
					function onInit()
						onUpdate = update();
					end

					function update()
						if window.isCustom() then
							if getValue() ~= window.class.getValue() then
								window.class.setValue(getValue());
							end
						end
					end

numberfieldX.script:
function action(draginfo)
	local charNode = DB.getChild(window.getDatabaseNode(), "...");
	local rActor = ActorManager.resolveActor(charNode);
	ActionSpellGain.performRoll(draginfo, rActor, ActionRMDice.Closed, window.name.getValue(), window.type.getValue(), getValue());
	return true;
end
function onDragStart(button, x, y, draginfo)
	return action(draginfo);
end
function onDoubleClick(x,y)
	return action();
end
